(function(){'use strict';if(typeof window === 'undefined')return;if(window.__imgOptimizerInit)return;window.__imgOptimizerInit = true;const PLACEHOLDER = 'data:image/svg+xml;base64,' + btoa('<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 1 1"><rect fill="#E8DFD0"/></svg>');function isWebpSupported(){return new Promise(resolve =>{const webp = 'data:image/webp;base64,UklGRiQAAABXRUJQVlA4IBgAAAAwAQCdASoBAAEAAUAmJaQAA3AA/v3AgAA=';const img = new Image();img.onload = img.onerror =()=> resolve(img.height === 1);img.src = webp;});}function optimizeImg(img){if(!img || !img.tagName || img.tagName.toLowerCase()!== 'img')return;if(img.__imgOptDone)return;img.__imgOptDone = true;if(!img.hasAttribute('loading')){const isHero = img.classList.contains('hero-img')|| img.closest('.galeri-ana,.hero,.slider-slayt,.banner-slide');const isAboveFold = img.getBoundingClientRect().top < window.innerHeight;if(!isHero && !isAboveFold){img.setAttribute('loading','lazy');}else{img.setAttribute('fetchpriority','high');}}if(!img.hasAttribute('decoding')){img.setAttribute('decoding','async');}if(!img.style.aspectRatio && !img.hasAttribute('width')&& !img.hasAttribute('height')){const parent = img.parentElement;if(parent){const parentStyle = getComputedStyle(parent);const aspectRatio = parentStyle.aspectRatio || '';if(aspectRatio){img.style.aspectRatio = aspectRatio;}}}if(img.src && !img.srcset && img.src.startsWith('/')){const baseUrl = img.src.replace(/\.(jpg|jpeg|png)$/i,'');const webpSet = `${baseUrl}.webp 1x`;img.srcset = webpSet;img.setAttribute('data-orig-src',img.src);}}function optimizeAll(){document.querySelectorAll('img').forEach(optimizeImg);}function init(){optimizeAll();const observer = new MutationObserver((mutations)=>{mutations.forEach(m =>{m.addedNodes.forEach(node =>{if(node.nodeType === 1){if(node.tagName === 'IMG'){optimizeImg(node);}else if(node.querySelectorAll){node.querySelectorAll('img').forEach(optimizeImg);}}});});});if(document.body){observer.observe(document.body,{childList:true,subtree:true});}else{document.addEventListener('DOMContentLoaded',()=> observer.observe(document.body,{childList:true,subtree:true}));}}if(document.readyState === 'loading'){document.addEventListener('DOMContentLoaded',init);}else{init();}if(window.MutationObserver){const spaObserver = new MutationObserver(()=> optimizeAll());if(document.body){spaObserver.observe(document.body,{childList:true,subtree:true});}}})();